create table checklists(id bigint primary key, unidade text, categoria text, momento text, frequencia text, horario_previsto text, responsavel_sugerido text, obrigatorio boolean, anexo_manual boolean, foto_ambiente boolean, campo_aberto text);
create table submissions(id uuid primary key, checklist_id bigint references checklists(id), operator_name text not null, unidade text not null, date date not null, filled_at timestamptz not null, status text not null, has_problem boolean default false, observacoes text, oknok text, passagem text);
create table submission_files(id uuid primary key default gen_random_uuid(), submission_id uuid references submissions(id), file_name text, file_path text, file_type text);
create table maintenance_records(id uuid primary key default gen_random_uuid(), submission_id uuid references submissions(id), date date, unidade text, checklist_origem text, area_praca text, item_problema text, descricao_problema text, responsible text, criticidade text, status text, prazo_retorno text, observacoes text);
